async (params, browser) => {
  // Search Substack
  await browser.open(`https://substack.com/search/${params.query}`)

  // Wait for search results
  await browser.waitForSelector('[class*=\'post\'], [class*=\'search-result\'], article, a[href*=\'/p/\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[class*="search-result"], [class*="post-preview"], article, [class*="SearchResult"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const titleEl = el.querySelector('h2, h3, [class*="title"] a, [class*="post-title"]'); const authorEl = el.querySelector('[class*="author"] a, [class*="byline"] a, [class*="pub-name"]'); const newsletterEl = el.querySelector('[class*="publication"], [class*="newsletter"]'); const likesEl = el.querySelector('[class*="like"] span, [class*="heart"] span, [class*="reaction"]'); const dateEl = el.querySelector('time, [class*="date"], [class*="timestamp"]'); const previewEl = el.querySelector('[class*="subtitle"], [class*="preview"], [class*="body-text"] p'); const linkEl = el.querySelector('a[href*="/p/"], a[href*=".substack.com"], h2 a, h3 a'); const imgEl = el.querySelector('img[src*="substackcdn"], img[src*="substack"], img'); results.push({ title: titleEl ? titleEl.textContent.trim() : '', author: authorEl ? authorEl.textContent.trim() : '', newsletter: newsletterEl ? newsletterEl.textContent.trim() : '', preview: previewEl ? previewEl.textContent.trim().substring(0, 200) : '', likes: likesEl ? likesEl.textContent.trim() : '', date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
